const express = require('express');
const router  = express.Router();
const db      = require('../config/db');
const { auth }= require('../middleware/auth');

router.get('/summary', auth, async (req, res) => {
  try {
    const userId = req.user.id;
    const month  = parseInt(req.query.month) || (new Date().getMonth() + 1);
    const year   = parseInt(req.query.year)  || new Date().getFullYear();

    let totalIncome = 0;
    try {
      const [[row]] = await db.execute(
        `SELECT COALESCE(SUM(amount), 0) AS v FROM income WHERE user_id = ? AND MONTH(date) = ? AND YEAR(date) = ?`,
        [userId, month, year]
      );
      totalIncome = parseFloat(row.v) || 0;
    } catch (e) { console.error('income err:', e.message); }

    let totalExpenses = 0;
    try {
      const [[row]] = await db.execute(
        `SELECT COALESCE(SUM(amount), 0) AS v FROM expenses WHERE user_id = ? AND MONTH(date) = ? AND YEAR(date) = ?`,
        [userId, month, year]
      );
      totalExpenses = parseFloat(row.v) || 0;
    } catch (e) { console.error('expenses err:', e.message); }

    let savingsGoals = { total: 0, completed: 0 };
    try {
      const [[row]] = await db.execute(
        `SELECT COUNT(*) AS total, SUM(CASE WHEN is_completed=1 THEN 1 ELSE 0 END) AS completed FROM savings_goals WHERE user_id = ?`,
        [userId]
      );
      savingsGoals = { total: parseInt(row.total)||0, completed: parseInt(row.completed)||0 };
    } catch (e) { console.error('goals err:', e.message); }

    let upcomingReminders = [];
    try {
      const [rows] = await db.execute(
        `SELECT * FROM reminders WHERE user_id = ? AND is_paid = 0 AND due_date BETWEEN CURDATE() AND DATE_ADD(CURDATE(), INTERVAL 7 DAY) ORDER BY due_date ASC LIMIT 5`,
        [userId]
      );
      upcomingReminders = rows;
    } catch (e) { console.error('reminders err:', e.message); }

    let recentExpenses = [];
    try {
      const [rows] = await db.execute(
        `SELECT * FROM expenses WHERE user_id = ? ORDER BY date DESC LIMIT 5`,
        [userId]
      );
      recentExpenses = rows;
    } catch (e) { console.error('recent err:', e.message); }

    let categoryBreakdown = [];
    try {
      const [rows] = await db.execute(
        `SELECT category, SUM(amount) AS total FROM expenses WHERE user_id = ? AND MONTH(date) = ? AND YEAR(date) = ? GROUP BY category`,
        [userId, month, year]
      );
      categoryBreakdown = rows;
    } catch (e) { console.error('category err:', e.message); }

    let monthlyTrend = [];
    try {
      for (let i = 5; i >= 0; i--) {
        const d = new Date(year, month - 1 - i, 1);
        const m = d.getMonth() + 1;
        const y = d.getFullYear();
        const [[expRow]] = await db.execute(
          `SELECT COALESCE(SUM(amount),0) AS v FROM expenses WHERE user_id=? AND MONTH(date)=? AND YEAR(date)=?`,
          [userId, m, y]
        );
        const [[incRow]] = await db.execute(
          `SELECT COALESCE(SUM(amount),0) AS v FROM income WHERE user_id=? AND MONTH(date)=? AND YEAR(date)=?`,
          [userId, m, y]
        );
        monthlyTrend.push({ month: m, year: y, expenses: parseFloat(expRow.v)||0, income: parseFloat(incRow.v)||0 });
      }
    } catch (e) { console.error('trend err:', e.message); }

    let unreadNotifications = 0;
    try {
      const [[row]] = await db.execute(
        `SELECT COUNT(*) AS v FROM notifications WHERE user_id=? AND is_read=0`,
        [userId]
      );
      unreadNotifications = parseInt(row.v)||0;
    } catch (e) { console.error('notif err:', e.message); }

    res.json({ totalIncome, totalExpenses, balance: totalIncome - totalExpenses, savingsGoals, upcomingReminders, recentExpenses, categoryBreakdown, monthlyTrend, unreadNotifications });

  } catch (err) {
    console.error('Dashboard fatal error:', err);
    res.status(500).json({ message: 'Dashboard failed', error: err.message });
  }
});

module.exports = router;
